class Solution:
    def findLexSmallestString(self, s, a, b):
        n = len(s)

        def apply_add(digits):
            out = list(digits)
            for i in range(1, n, 2):
                out[i] = (out[i] + a) % 10
            return tuple(out)

        def apply_rotate(digits):
            k = b % n
            return tuple(digits[n - k:]) + tuple(digits[:n - k])

        start = tuple(int(ch) for ch in s)
        best = start
        stack = [start]
        seen = {start}
        while stack:
            cur = stack.pop()
            if cur < best:
                best = cur
            for nxt in (apply_rotate(cur), apply_add(cur)):
                if nxt not in seen:
                    seen.add(nxt)
                    stack.append(nxt)
        return ''.join(str(d) for d in best)

