class Solution:
    def findLexSmallestString(self, s: str, a: int, b: int) -> str:
        n = len(s)

        def add(t: str) -> str:
            chars = list(t)
            for i in range(1, n, 2):
                chars[i] = str((int(chars[i]) + a) % 10)
            return ''.join(chars)

        def rotate(t: str) -> str:
            k = b % n
            return t[n - k:] + t[:n - k]

        best = s
        visited = {s}
        from collections import deque
        queue = deque([s])
        while queue:
            cur = queue.popleft()
            for nxt in (add(cur), rotate(cur)):
                if nxt not in visited:
                    visited.add(nxt)
                    if nxt < best:
                        best = nxt
                    queue.append(nxt)
        return best

