var findLexSmallestString = function(s, a, b) {
    const n = s.length;
    const add = (t) => {
        const chars = t.split('');
        for (let i = 1; i < n; i += 2) {
            chars[i] = String((Number(chars[i]) + a) % 10);
        }
        return chars.join('');
    };
    const rotate = (t) => {
        const k = b % n;
        return t.slice(n - k) + t.slice(0, n - k);
    };
    let best = s;
    const visited = new Set([s]);
    const queue = [s];
    let head = 0;
    while (head < queue.length) {
        const cur = queue[head++];
        for (const nxt of [add(cur), rotate(cur)]) {
            if (!visited.has(nxt)) {
                visited.add(nxt);
                if (nxt < best) best = nxt;
                queue.push(nxt);
            }
        }
    }
    return best;
};
